mapper.update:
UPDATE outbound
type=#{type}, quantity=#{quantity}, unit_price=#{unitPrice}, total_amount=#{totalAmount}, recipient=#{recipient}, department=#{department}, remark=#{remark}, status=#{status}, updated_at=#{updatedAt},
WHERE id=#{id}

mapper.select:
SELECT * FROM outbound


        AND id = #{id}


        AND outbound_no LIKE CONCAT('%', #{outboundNo}, '%')


        AND type = #{type}


        AND material_id = #{materialId}


        AND warehouse_id = #{warehouseId}


        AND operator_id = #{operatorId}


        AND created_at >= #{startTime}


        AND created_at <= #{endTime}


ORDER BY created_at DESC
